eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   tema1: () => (/* binding */ tema1)\n/* harmony export */ });\nconst tema1 = {\n    id: 1,\n    titulo: \"An\\xe1lisis de eficiencia\",\n    subtitulo: \"C\\xf3mo medir y comparar el rendimiento de algoritmos\",\n    descripcion: \"Aprende a calcular el coste de un algoritmo usando notaci\\xf3n asint\\xf3tica y a distinguir entre O, Ω y Θ.\",\n    color: \"from-blue-500 to-blue-700\",\n    icono: \"⏱️\",\n    topicKey: \"Tema 1_ Costes\",\n    duracion: \"40 min\",\n    sections: [\n        {\n            id: \"por-que\",\n            titulo: \"\\xbfPor qu\\xe9 importa la eficiencia?\",\n            tipo: \"intro\",\n            icono: \"\\uD83D\\uDE80\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Un programa que funciona pero tarda a\\xf1os en dar la respuesta es in\\xfatil. La eficiencia importa porque hay problemas que, con un algoritmo malo, requieren m\\xe1s tiempo del que tiene el universo — aunque uses el ordenador m\\xe1s r\\xe1pido del mundo.\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: \"El ejemplo de la pandemia\",\n                    contenido: \"Si el n\\xfamero de infectados se duplica cada 3 d\\xedas partiendo de 1, en 60 d\\xedas hay m\\xe1s de un mill\\xf3n. En 90 d\\xedas, mil millones. El crecimiento exponencial hace que un algoritmo O(2^n) sea pr\\xe1cticamente inutilizable para n > 50.\"\n                },\n                {\n                    tipo: \"tabla\",\n                    cabeceras: [\n                        \"n\",\n                        \"O(log n)\",\n                        \"O(n)\",\n                        \"O(n log n)\",\n                        \"O(n\\xb2)\",\n                        \"O(2^n)\"\n                    ],\n                    filas: [\n                        [\n                            \"10\",\n                            \"3\",\n                            \"10\",\n                            \"33\",\n                            \"100\",\n                            \"1.024\"\n                        ],\n                        [\n                            \"100\",\n                            \"7\",\n                            \"100\",\n                            \"664\",\n                            \"10.000\",\n                            \"10^30\"\n                        ],\n                        [\n                            \"1.000\",\n                            \"10\",\n                            \"1.000\",\n                            \"10.000\",\n                            \"1.000.000\",\n                            \"10^301\"\n                        ],\n                        [\n                            \"1.000.000\",\n                            \"20\",\n                            \"1M\",\n                            \"20M\",\n                            \"10^12\",\n                            \"imposible\"\n                        ]\n                    ]\n                },\n                {\n                    tipo: \"texto\",\n                    contenido: \"A partir de un tama\\xf1o suficientemente grande, un algoritmo de coste constante SIEMPRE ser\\xe1 mejor que uno cuadr\\xe1tico, aunque para datos peque\\xf1os el cuadr\\xe1tico pueda parecer m\\xe1s r\\xe1pido.\"\n                }\n            ]\n        },\n        {\n            id: \"coste\",\n            titulo: \"El coste de un algoritmo\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDCD0\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: 'El coste mide cu\\xe1ntos \"recursos\" (tiempo o memoria) consume un algoritmo en funci\\xf3n del tama\\xf1o de la entrada. Lo que nos interesa no es el tiempo en segundos (depende del hardware), sino c\\xf3mo crece el n\\xfamero de operaciones al aumentar n.'\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"Caso mejor, caso peor y caso promedio\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"comparacion\",\n                    lado1: {\n                        titulo: \"✅ Caso peor (lo que usamos)\",\n                        items: [\n                            \"Cota superior fiable para todos los casos\",\n                            \"M\\xe1s f\\xe1cil de calcular\",\n                            \"Garantiza que nunca tardaremos m\\xe1s\",\n                            \"Ejemplo: buscar en vector → el elemento no est\\xe1\"\n                        ]\n                    },\n                    lado2: {\n                        titulo: \"⚖️ Caso promedio (a veces)\",\n                        items: [\n                            \"Requiere conocer distribuci\\xf3n de datos\",\n                            \"M\\xe1s complejo de calcular\",\n                            \"\\xdatil para an\\xe1lisis estad\\xedstico\",\n                            \"Ejemplo: Quicksort → O(n log n) en promedio\"\n                        ]\n                    }\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"tip\",\n                    contenido: \"En este curso nos centramos siempre en el CASO PEOR. Es la forma est\\xe1ndar de analizar algoritmos porque da una garant\\xeda para todos los datos posibles.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Ejemplo: b\\xfasqueda lineal\",\n                    lenguaje: \"cpp\",\n                    contenido: `bool search(const vector<T>& v, const T& x) {\n    int i = 0;\n    while (i < v.size() && v[i] != x) {\n        ++i;\n    }\n    return i < v.size();\n}`,\n                    explicacion: \"Caso mejor: x est\\xe1 en v[0] → 1 comparaci\\xf3n → O(1). Caso peor: x no est\\xe1 → n comparaciones → O(n).\"\n                }\n            ]\n        },\n        {\n            id: \"notacion\",\n            titulo: \"Notaci\\xf3n asint\\xf3tica: O, Ω y Θ\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDD23\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Las tres notaciones describen el comportamiento de una funci\\xf3n para valores de n suficientemente grandes. No nos importan las constantes ni los t\\xe9rminos de menor orden.\"\n                },\n                {\n                    tipo: \"tabla\",\n                    cabeceras: [\n                        \"Notaci\\xf3n\",\n                        \"Significado\",\n                        \"Dice que…\"\n                    ],\n                    filas: [\n                        [\n                            \"O(g(n))\",\n                            \"Cota superior\",\n                            \"f(n) crece como mucho igual que g(n)\"\n                        ],\n                        [\n                            \"Ω(g(n))\",\n                            \"Cota inferior\",\n                            \"f(n) crece al menos igual que g(n)\"\n                        ],\n                        [\n                            \"Θ(g(n))\",\n                            \"Cota ajustada\",\n                            \"f(n) crece exactamente igual que g(n)\"\n                        ]\n                    ]\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"warning\",\n                    titulo: \"Error t\\xedpico\",\n                    contenido: 'Confundir O con Θ. Decir \"la b\\xfasqueda lineal es O(n)\" es correcto pero impreciso: tambi\\xe9n es O(n\\xb2) o O(n!). Lo correcto es Θ(n) cuando queremos la cota ajustada.'\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"Reglas pr\\xe1cticas\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"Regla de la suma: O(f) + O(g) = O(max(f, g))  →  O(n\\xb2 + n) = O(n\\xb2)\",\n                        \"Regla del producto: O(f) \\xb7 O(g) = O(f \\xb7 g)  →  O(n) \\xb7 O(log n) = O(n log n)\",\n                        \"Constantes: O(5n) = O(n)  →  los factores constantes se ignoran\",\n                        \"Logaritmos: O(log₂ n) = O(log₁₀ n) = O(log n)  →  la base no importa\"\n                    ]\n                },\n                {\n                    tipo: \"formula\",\n                    contenido: \"O(1) ⊂ O(log n) ⊂ O(n) ⊂ O(n log n) ⊂ O(n\\xb2) ⊂ O(n\\xb3) ⊂ O(2^n) ⊂ O(n!)\",\n                    explicacion: \"Esta es la jerarqu\\xeda de \\xf3rdenes de complejidad. Cada uno crece m\\xe1s r\\xe1pido que el anterior.\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: '\\xbfCu\\xe1ndo un algoritmo es \"preferible\"?',\n                    contenido: \"Un algoritmo de coste O(1) SIEMPRE es preferible a uno O(n\\xb2) si el tama\\xf1o de los datos es suficientemente grande. Para tama\\xf1os peque\\xf1os, el constante podr\\xeda no serlo. En los tests preguntan esto con frecuencia.\"\n                }\n            ]\n        },\n        {\n            id: \"iterativos\",\n            titulo: \"An\\xe1lisis de algoritmos iterativos\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDD04\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Para calcular el coste de un algoritmo iterativo, el truco es analizar el n\\xfamero de veces que se ejecuta cada instrucci\\xf3n dentro de los bucles.\"\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"Bucle simple\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Bucle simple — O(n)\",\n                    lenguaje: \"cpp\",\n                    contenido: `for (int i = 0; i < n; i++) {\n    // instrucción de coste constante O(1)\n    a++;\n}`,\n                    explicacion: \"El cuerpo se ejecuta n veces con coste O(1) cada vez → total O(n).\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Bucles anidados — O(n\\xb2)\",\n                    lenguaje: \"cpp\",\n                    contenido: `for (int i = 0; i < n; i++) {\n    for (int j = 0; j < n; j++) {\n        a++;  // O(1)\n    }\n}`,\n                    explicacion: \"Bucle externo: n veces. Bucle interno: n veces por cada iteraci\\xf3n externa → n \\xd7 n = O(n\\xb2).\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Bucle que divide — O(log n)\",\n                    lenguaje: \"cpp\",\n                    contenido: `int i = n;\nwhile (i > 1) {\n    i = i / 2;  // se divide entre 2 cada vez\n}`,\n                    explicacion: \"Cada iteraci\\xf3n divide i entre 2. Para llegar de n a 1 hacen falta log₂(n) pasos → O(log n).\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Bucle con variable externa — O(max(n,m)) o similar\",\n                    lenguaje: \"cpp\",\n                    contenido: `int a = 0;\nfor (int i = 0, j = m; (i < n) || (j > 0); ++i, --j)\n    a--;`,\n                    explicacion: \"El bucle termina cuando AMBAS condiciones fallan. Si n=5 y m=30, termina en max(n,m)=30 pasos. Si n=30 y m=5, termina en 30. El coste es Θ(max(n,m)).\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"warning\",\n                    titulo: \"Trampa frecuente: condici\\xf3n OR en bucle\",\n                    contenido: \"Con (i < n) || (j > 0), el bucle sigue mientras AL MENOS UNA condici\\xf3n sea verdadera. El peor caso es cuando ambas variables se mueven lento. Con m=30 fijo, el bucle siempre hace exactamente 30 iteraciones → Θ(1) porque m es constante.\"\n                },\n                {\n                    tipo: \"ejemplo\",\n                    titulo: \"Algoritmo de ordenaci\\xf3n por selecci\\xf3n\",\n                    bloques: [\n                        {\n                            tipo: \"codigo\",\n                            lenguaje: \"cpp\",\n                            contenido: `void ordenaSeleccion(int v[], int n) {\n    for (int i = 0; i < n-1; i++) {    // n-1 veces\n        int pmin = i;\n        for (int j = i+1; j < n; j++)  // n-i-1 veces\n            if (v[j] < v[pmin])\n                pmin = j;\n        swap(v[i], v[pmin]);\n    }\n}`\n                        },\n                        {\n                            tipo: \"texto\",\n                            contenido: \"El bucle interior ejecuta (n-1) + (n-2) + ... + 1 = n(n-1)/2 comparaciones en total. Por la regla de sumas: Θ(n\\xb2). La ordenaci\\xf3n por selecci\\xf3n siempre es Θ(n\\xb2) en el caso peor Y mejor.\"\n                        }\n                    ]\n                }\n            ]\n        },\n        {\n            id: \"reduccion\",\n            titulo: \"Algoritmos por reducci\\xf3n vs. divisi\\xf3n\",\n            tipo: \"concepto\",\n            icono: \"✂️\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"En algoritmos recursivos, el coste se calcula con recurrencias. Hay dos esquemas b\\xe1sicos seg\\xfan c\\xf3mo se reduce el tama\\xf1o del problema:\"\n                },\n                {\n                    tipo: \"comparacion\",\n                    lado1: {\n                        titulo: \"Por sustracci\\xf3n (T(n) = aT(n-b) + f(n))\",\n                        items: [\n                            \"Se resta b al problema (b constante)\",\n                            \"a=1: coste polin\\xf3mico si f es polin\\xf3mica\",\n                            \"a>1: SIEMPRE exponencial → a^(n/b)\",\n                            \"Ejemplo: fibonacci → a=2, b=1 → O(2^n)\"\n                        ]\n                    },\n                    lado2: {\n                        titulo: \"Por divisi\\xf3n (T(n) = aT(n/b) + f(n))\",\n                        items: [\n                            \"Se divide entre b el problema\",\n                            \"f(n)∈Θ(n^k): usa el Teorema de la divisi\\xf3n\",\n                            \"a < b^k → Θ(n^k)\",\n                            \"a = b^k → Θ(n^k \\xb7 log n)\",\n                            \"a > b^k → Θ(n^(log_b a))\"\n                        ]\n                    }\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"danger\",\n                    titulo: \"Clave de examen\",\n                    contenido: \"Si a > 1 en reducci\\xf3n por SUSTRACCI\\xd3N, el coste siempre es exponencial (Θ(a^(n/b))), sin importar cu\\xe1nto valga b. Esto es un resultado contraintuitivo que sale mucho en tests.\"\n                }\n            ]\n        },\n        {\n            id: \"errores\",\n            titulo: \"Errores frecuentes\",\n            tipo: \"errores\",\n            icono: \"⚠️\",\n            bloques: [\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Confundir O con Θ\",\n                    malo: \"2^n + n^10 ∈ O(n^10)\",\n                    bien: \"2^n + n^10 ∈ Θ(2^n)  [por regla de la suma]\",\n                    explicacion: \"O solo requiere que f(n) ≤ c\\xb7g(n) para n suficientemente grande. Θ requiere tanto la cota superior como inferior.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Olvidar que el bucle tambi\\xe9n puede ser el mejor caso\",\n                    malo: \"El caso mejor de comprobar si un vector es creciente es O(n)\",\n                    bien: \"El caso mejor es O(1): si el primer par no cumple la propiedad, se detiene inmediatamente\",\n                    explicacion: 'El caso mejor ocurre cuando encontramos el \"fallo\" en la primera iteraci\\xf3n.'\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"No considerar los bucles condicionados\",\n                    malo: \"while (b && i < n) → siempre O(n)\",\n                    bien: \"Si b se pone a false en la primera iteraci\\xf3n → O(1)\",\n                    explicacion: \"Cuando hay una condici\\xf3n booleana como &&, el caso mejor puede ser O(1) si la condici\\xf3n booleana falla inmediatamente.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Inserci\\xf3n en vector sin repetidos\",\n                    malo: \"Solo hay que a\\xf1adir el elemento al final → O(1)\",\n                    bien: \"Hay que BUSCAR si ya existe antes de insertar → O(n)\",\n                    explicacion: \"La b\\xfasqueda en un vector no ordenado requiere recorrerlo completo en el caso peor.\"\n                }\n            ]\n        },\n        {\n            id: \"resumen\",\n            titulo: \"Resumen y conexi\\xf3n con los tests\",\n            tipo: \"tests\",\n            icono: \"\\uD83C\\uDFAF\",\n            bloques: [\n                {\n                    tipo: \"alerta\",\n                    nivel: \"success\",\n                    titulo: \"Lo m\\xe1s importante de este tema\",\n                    contenido: \"1) Θ es la cota ajustada, O es cota superior. 2) Caso peor es lo que usamos. 3) Reducci\\xf3n por sustracci\\xf3n con a>1 → exponencial. 4) Bucle que divide → logar\\xedtmico.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"Las preguntas de examen suelen dar un fragmento de c\\xf3digo y pedir el coste Θ exacto\",\n                        \"Ojo con bucles que tienen condici\\xf3n OR (||): el peor caso es cuando las dos variables se mueven independientemente\",\n                        \"Recuerda: O(1) es mejor que O(n\\xb2) solo cuando n es suficientemente grande\",\n                        'La frase \"ninguna de las anteriores\" aparece cuando el coste correcto no est\\xe1 en las opciones'\n                    ]\n                }\n            ]\n        }\n    ]\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/lessons/tema1.ts\n");

