eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   tema2: () => (/* binding */ tema2)\n/* harmony export */ });\nconst tema2 = {\n    id: 2,\n    titulo: \"Especificaci\\xf3n de algoritmos\",\n    subtitulo: \"C\\xf3mo describir formalmente qu\\xe9 hace un algoritmo\",\n    descripcion: \"Aprende a escribir especificaciones pre/post correctas usando l\\xf3gica de primer orden y cuantificadores.\",\n    color: \"from-violet-500 to-violet-700\",\n    icono: \"\\uD83D\\uDCCB\",\n    topicKey: \"Tema 3_ Dise\\xf1o de algoritmos iterativos\",\n    duracion: \"35 min\",\n    sections: [\n        {\n            id: \"que-es\",\n            titulo: \"\\xbfQu\\xe9 es especificar?\",\n            tipo: \"intro\",\n            icono: \"\\uD83C\\uDFAF\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Especificar es describir QU\\xc9 hace un algoritmo, sin decir C\\xd3MO lo hace. Es un contrato entre el usuario (quien llama a la funci\\xf3n) y el implementador (quien la escribe). La especificaci\\xf3n es independiente del lenguaje de programaci\\xf3n.\"\n                },\n                {\n                    tipo: \"comparacion\",\n                    lado1: {\n                        titulo: \"\\uD83D\\uDCDD Especificar (QU\\xc9)\",\n                        items: [\n                            \"Describe el problema a resolver\",\n                            \"Define qu\\xe9 datos acepta (precondici\\xf3n)\",\n                            \"Define qu\\xe9 garantiza producir (postcondici\\xf3n)\",\n                            \"No dice c\\xf3mo implementarlo\",\n                            \"Lenguaje: l\\xf3gica de predicados\"\n                        ]\n                    },\n                    lado2: {\n                        titulo: \"\\uD83D\\uDCBB Implementar (C\\xd3MO)\",\n                        items: [\n                            \"Escribe el c\\xf3digo que resuelve el problema\",\n                            \"Debe cumplir la especificaci\\xf3n\",\n                            \"Puede haber m\\xfaltiples implementaciones v\\xe1lidas\",\n                            \"Lenguaje: C++, Python, etc.\",\n                            \"Solo v\\xe1lida si cumple pre/post\"\n                        ]\n                    }\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: \"La especificaci\\xf3n como contrato\",\n                    contenido: \"Si el usuario llama a la funci\\xf3n cumpliendo la precondici\\xf3n, el implementador garantiza que se cumple la postcondici\\xf3n. Si el usuario viola la precondici\\xf3n, no se puede garantizar nada sobre el resultado.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Ejemplo: sin especificaci\\xf3n (ambiguo)\",\n                    lenguaje: \"cpp\",\n                    contenido: `bool essuma(const vector<int>& v, int n)`,\n                    explicacion: '\\xbfQu\\xe9 pasa si n=0? \\xbfSi n es negativo? \\xbfSi n > v.size()? \\xbfQu\\xe9 significa \"suma de los anteriores\" para v[0]? La cabecera sola no responde nada.'\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Con especificaci\\xf3n (preciso)\",\n                    lenguaje: \"cpp\",\n                    contenido: `// {0 ≤ n ≤ 1000}\nbool essuma(const vector<int>& v, const int n)  /* dev b */\n// {b = ∃i: 0 ≤ i < n : v[i] = Σj: 0 ≤ j < i : v[j]}`,\n                    explicacion: \"Ahora est\\xe1 claro: n debe ser [0, 1000]. Si n=0 devuelve false. Si v[0]=0 devuelve true (suma de ning\\xfan elemento anterior = 0).\"\n                }\n            ]\n        },\n        {\n            id: \"logica\",\n            titulo: \"L\\xf3gica de primer orden: lo que necesitas saber\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDD23\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Para escribir especificaciones usamos l\\xf3gica de primer orden. No necesitas saber todo — solo las construcciones que aparecen en este curso.\"\n                },\n                {\n                    tipo: \"tabla\",\n                    cabeceras: [\n                        \"S\\xedmbolo\",\n                        \"Nombre\",\n                        \"Ejemplo\",\n                        \"Significado\"\n                    ],\n                    filas: [\n                        [\n                            \"∧\",\n                            \"Y l\\xf3gico (AND)\",\n                            \"P ∧ Q\",\n                            \"P y Q son verdad\"\n                        ],\n                        [\n                            \"∨\",\n                            \"O l\\xf3gico (OR)\",\n                            \"P ∨ Q\",\n                            \"P o Q (o ambos)\"\n                        ],\n                        [\n                            \"\\xac\",\n                            \"Negaci\\xf3n\",\n                            \"\\xacP\",\n                            \"P es falso\"\n                        ],\n                        [\n                            \"→\",\n                            \"Implicaci\\xf3n\",\n                            \"P → Q\",\n                            \"Si P entonces Q\"\n                        ],\n                        [\n                            \"∀i: R: P\",\n                            \"Para todo\",\n                            \"∀i: 0≤i<n: v[i]≥0\",\n                            \"Para todo i en rango R, P es cierto\"\n                        ],\n                        [\n                            \"∃i: R: P\",\n                            \"Existe\",\n                            \"∃i: 0≤i<n: v[i]=x\",\n                            \"Existe alg\\xfan i en R donde P es cierto\"\n                        ],\n                        [\n                            \"Σi: R: e\",\n                            \"Suma\",\n                            \"Σi: 0≤i<n: v[i]\",\n                            \"Suma de e para todo i en R\"\n                        ],\n                        [\n                            \"#i: R: P\",\n                            \"Cuenta\",\n                            \"#i: 0≤i<n: v[i]>0\",\n                            \"N\\xfamero de i en R donde P es cierto\"\n                        ],\n                        [\n                            \"Πi: R: e\",\n                            \"Producto\",\n                            \"Πi: 0≤i<n: a[i]\",\n                            \"Producto de e para todo i en R\"\n                        ],\n                        [\n                            \"↑i: R: e\",\n                            \"M\\xe1ximo\",\n                            \"↑i: 0≤i<n: v[i]\",\n                            \"M\\xe1ximo de e para todo i en R\"\n                        ]\n                    ]\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"tip\",\n                    titulo: \"Notaci\\xf3n de la asignatura\",\n                    contenido: \"La notaci\\xf3n cuantificada usa la forma: OPERADOR variable: RANGO: EXPRESI\\xd3N. El rango delimita los valores de la variable. Si el rango es vac\\xedo, la suma vale 0, el producto vale 1, el m\\xe1ximo no est\\xe1 definido.\"\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"Ejemplos de predicados\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Predicados t\\xedpicos en especificaciones\",\n                    lenguaje: \"cpp\",\n                    contenido: `// ∀i: 0 ≤ i < n : v[i] ≥ 0\n//   \"todos los elementos de v[0..n) son no negativos\"\n\n// ∃j: 0 ≤ j < n : v[j] = x\n//   \"existe algún elemento en v[0..n) igual a x\"\n\n// Σi: 0 ≤ i < n : v[i]\n//   \"suma de todos los elementos de v[0..n)\"\n\n// #i: 0 ≤ i < n : v[i] % 2 = 0\n//   \"cantidad de elementos pares en v[0..n)\"\n\n// ∀i: 0 ≤ i < n-1 : v[i] ≤ v[i+1]\n//   \"v está ordenado de forma no decreciente\"`\n                }\n            ]\n        },\n        {\n            id: \"especificacion-funciones\",\n            titulo: \"C\\xf3mo escribir una especificaci\\xf3n completa\",\n            tipo: \"concepto\",\n            icono: \"✍️\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Una especificaci\\xf3n completa tiene tres partes: la precondici\\xf3n (entre llaves antes), la cabecera de la funci\\xf3n, y la postcondici\\xf3n (entre llaves despu\\xe9s).\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Estructura general\",\n                    lenguaje: \"cpp\",\n                    contenido: `// {PRECONDICIÓN}\ntipo_retorno nombreFuncion(tipo param)  /* dev nombre_retorno */\n// {POSTCONDICIÓN}`,\n                    explicacion: \"La precondici\\xf3n describe qu\\xe9 debe cumplir la entrada. La postcondici\\xf3n relaciona la entrada con la salida.\"\n                },\n                {\n                    tipo: \"ejemplo\",\n                    titulo: \"Especificaci\\xf3n: contar pares\",\n                    bloques: [\n                        {\n                            tipo: \"codigo\",\n                            lenguaje: \"cpp\",\n                            contenido: `// {0 ≤ n ≤ longitud(a)}\nint contarPares(const vector<int>& a, const int n)  /* dev c */\n// {c = #i: 0 ≤ i < n : a[i] % 2 = 0}`\n                        },\n                        {\n                            tipo: \"texto\",\n                            contenido: \"La precondici\\xf3n dice que n es v\\xe1lido. La postcondici\\xf3n dice que c es exactamente el n\\xfamero de pares en a[0..n).\"\n                        }\n                    ]\n                },\n                {\n                    tipo: \"ejemplo\",\n                    titulo: \"Especificaci\\xf3n: producto de array\",\n                    bloques: [\n                        {\n                            tipo: \"codigo\",\n                            lenguaje: \"cpp\",\n                            contenido: `// {0 ≤ n ≤ longitud(a)}\nint producto(const vector<int>& a, const int n)  /* dev p */\n// {p = Πi: 0 ≤ i < n : a[i]}`\n                        },\n                        {\n                            tipo: \"alerta\",\n                            nivel: \"info\",\n                            contenido: \"Si n=0, el rango 0 ≤ i < 0 est\\xe1 vac\\xedo. El producto vac\\xedo es 1 (el elemento neutro del producto), por convenio.\"\n                        }\n                    ]\n                },\n                {\n                    tipo: \"ejemplo\",\n                    titulo: \"Especificaci\\xf3n: b\\xfasqueda binaria\",\n                    bloques: [\n                        {\n                            tipo: \"codigo\",\n                            lenguaje: \"cpp\",\n                            contenido: `// {0 ≤ n ≤ longitud(v)  ∧  ∀i: 0 ≤ i < n-1 : v[i] ≤ v[i+1]}\npair<bool,int> busquedaBinaria(const vector<int>& v, const int n, const int x)  /* dev (b,p) */\n// {(b ∧ v[p] = x ∧ 0 ≤ p < n)  ∨  (¬b ∧ ∀i: 0 ≤ i < n: v[i] ≠ x)}`\n                        },\n                        {\n                            tipo: \"texto\",\n                            contenido: \"La precondici\\xf3n exige que el vector est\\xe9 ordenado. La postcondici\\xf3n dice: o bien encontramos x en la posici\\xf3n p, o bien x no est\\xe1 en v.\"\n                        }\n                    ]\n                }\n            ]\n        },\n        {\n            id: \"propiedades\",\n            titulo: \"Propiedades de especificaciones\",\n            tipo: \"concepto\",\n            icono: \"⚡\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Una buena especificaci\\xf3n debe ser precisa (sin ambig\\xfcedades), breve (m\\xe1s corta que el c\\xf3digo) y clara (transmite la intuici\\xf3n). Tres propiedades que a veces est\\xe1n en tensi\\xf3n.\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"warning\",\n                    titulo: \"Precondici\\xf3n m\\xe1s d\\xe9bil posible\",\n                    contenido: \"Queremos que la funci\\xf3n sea aplicable al mayor n\\xfamero de entradas posibles. Por eso buscamos la precondici\\xf3n m\\xe1s d\\xe9bil (menos restrictiva) que permita garantizar la postcondici\\xf3n.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"Fortalecimiento de precondici\\xf3n: si {P} A {Q}, entonces {P' ⇒ P} A {Q}. Hacer la precondici\\xf3n m\\xe1s restrictiva sigue siendo v\\xe1lido.\",\n                        \"Debilitamiento de postcondici\\xf3n: si {P} A {Q} y Q ⇒ Q', entonces {P} A {Q'}. Una postcondici\\xf3n menos precisa tambi\\xe9n se cumple.\"\n                    ]\n                }\n            ]\n        },\n        {\n            id: \"errores\",\n            titulo: \"Errores frecuentes\",\n            tipo: \"errores\",\n            icono: \"⚠️\",\n            bloques: [\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Olvidar que el rango vac\\xedo tiene valor definido\",\n                    malo: \"Si n=0, la suma Σi: 0≤i<0: v[i] no est\\xe1 definida\",\n                    bien: \"El rango vac\\xedo da el elemento neutro: suma=0, producto=1\",\n                    explicacion: \"En l\\xf3gica, ∀i en rango vac\\xedo es true. ∃i en rango vac\\xedo es false. La suma vac\\xeda es 0.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Confundir precondici\\xf3n con la aserci\\xf3n del c\\xf3digo\",\n                    malo: \"La precondici\\xf3n es parte del c\\xf3digo y se ejecuta\",\n                    bien: \"La precondici\\xf3n es solo una anotaci\\xf3n formal. No se compila.\",\n                    explicacion: \"En C++ las precondiciones/postcondiciones van como comentarios // { ... }. No son c\\xf3digo ejecutable.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Postcondici\\xf3n que no diferencia bien\",\n                    malo: \"Si el valor no est\\xe1: {b = false}\",\n                    bien: \"{(b ∧ v[p]=x) ∨ (\\xacb ∧ ∀i: 0≤i<n: v[i]≠x)}\",\n                    explicacion: \"La postcondici\\xf3n debe cubrir TODOS los casos posibles y relacionar la salida con la entrada de forma un\\xedvoca.\"\n                }\n            ]\n        },\n        {\n            id: \"resumen\",\n            titulo: \"Resumen y conexi\\xf3n con tests\",\n            tipo: \"tests\",\n            icono: \"\\uD83C\\uDFAF\",\n            bloques: [\n                {\n                    tipo: \"alerta\",\n                    nivel: \"success\",\n                    titulo: \"Lo m\\xe1s importante\",\n                    contenido: \"1) Especificar es definir QU\\xc9, no C\\xd3MO. 2) Precondici\\xf3n = obligaci\\xf3n del usuario. Postcondici\\xf3n = garant\\xeda del implementador. 3) Domina los cuantificadores ∀, ∃, Σ, #. 4) El rango vac\\xedo tiene valores definidos.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"En los tests te dan una especificaci\\xf3n y preguntan qu\\xe9 hace la funci\\xf3n o si un invariante es correcto\",\n                        \"Practica leer predicados con cuantificadores: identifica el rango y la propiedad\",\n                        \"Distingue bien entre ∀ (para todo, m\\xe1s fuerte) y ∃ (existe alguno, m\\xe1s d\\xe9bil)\",\n                        \"Los invariantes de bucle del Tema 3 se escriben igual que las especificaciones pre/post\"\n                    ]\n                }\n            ]\n        }\n    ]\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/lessons/tema2.ts\n");

