eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   tema3: () => (/* binding */ tema3)\n/* harmony export */ });\nconst tema3 = {\n    id: 3,\n    titulo: \"Algoritmos iterativos\",\n    subtitulo: \"Verificaci\\xf3n y derivaci\\xf3n de bucles correctos\",\n    descripcion: \"Aprende a demostrar que un bucle es correcto usando invariantes y sem\\xe1ntica axiom\\xe1tica, y a derivar algoritmos desde su especificaci\\xf3n.\",\n    color: \"from-emerald-500 to-emerald-700\",\n    icono: \"\\uD83D\\uDD04\",\n    topicKey: \"Tema 3_ Dise\\xf1o de algoritmos iterativos\",\n    duracion: \"55 min\",\n    sections: [\n        {\n            id: \"motivacion\",\n            titulo: \"\\xbfPor qu\\xe9 verificar?\",\n            tipo: \"intro\",\n            icono: \"\\uD83E\\uDD14\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Programar no es suficiente: necesitamos saber que lo que hemos programado ES CORRECTO. El testing solo muestra que no hay errores en los casos probados. La verificaci\\xf3n formal demuestra que el programa es correcto para TODOS los casos posibles.\"\n                },\n                {\n                    tipo: \"comparacion\",\n                    lado1: {\n                        titulo: \"\\uD83E\\uDDEA Testing\",\n                        items: [\n                            \"Solo prueba casos concretos\",\n                            '\"No hay errores en estos 100 casos\"',\n                            \"No garantiza correcci\\xf3n total\",\n                            \"\\xdatil en la pr\\xe1ctica, pero no suficiente\"\n                        ]\n                    },\n                    lado2: {\n                        titulo: \"✅ Verificaci\\xf3n formal\",\n                        items: [\n                            \"Razona sobre TODOS los casos\",\n                            '\"El programa es correcto para cualquier entrada v\\xe1lida\"',\n                            \"Garantiza correcci\\xf3n total\",\n                            \"Permite tambi\\xe9n DERIVAR algoritmos\"\n                        ]\n                    }\n                },\n                {\n                    tipo: \"texto\",\n                    contenido: \"En este tema usamos la sem\\xe1ntica axiom\\xe1tica de Hoare: un sistema de reglas que nos permite razonar sobre instrucciones C++ sin ejecutarlas.\"\n                }\n            ]\n        },\n        {\n            id: \"reglas-basicas\",\n            titulo: \"Reglas b\\xe1sicas de verificaci\\xf3n\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDCD0\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: 'Una tripleta de Hoare {P} A {Q} significa: \"si se ejecuta A partiendo de un estado que satisface P, y A termina, entonces el estado final satisface Q\".'\n                },\n                {\n                    tipo: \"tabla\",\n                    cabeceras: [\n                        \"Regla\",\n                        \"Condici\\xf3n\",\n                        \"Resultado\"\n                    ],\n                    filas: [\n                        [\n                            \"Fortalecimiento precondici\\xf3n\",\n                            \"P' ⇒ P  y  {P} A {Q}\",\n                            \"{P'} A {Q}\"\n                        ],\n                        [\n                            \"Debilitamiento postcondici\\xf3n\",\n                            \"{P} A {Q}  y  Q ⇒ Q'\",\n                            \"{P} A {Q'}\"\n                        ],\n                        [\n                            \"Instrucci\\xf3n vac\\xeda\",\n                            \"—\",\n                            \"{P} skip {P}\"\n                        ],\n                        [\n                            \"Asignaci\\xf3n\",\n                            \"—\",\n                            \"{Q[x←e]} x=e {Q}\"\n                        ],\n                        [\n                            \"Secuencia\",\n                            \"{P}A{R}  y  {R}B{Q}\",\n                            \"{P} A;B {Q}\"\n                        ]\n                    ]\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"warning\",\n                    titulo: \"La asignaci\\xf3n se verifica al rev\\xe9s\",\n                    contenido: \"Para {P} x=e {Q}, calculamos P = Q[x←e]: sustituimos x por e en Q y ese es el P necesario. Ejemplo: {Q[x←e]} = {y=x+1}[x←3] = {y=4}.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Ejemplo: verificar una asignaci\\xf3n\",\n                    lenguaje: \"cpp\",\n                    contenido: `// Queremos demostrar: {n ≥ 0} y = n + 1 {y > 0}\n// Calculamos pmd(y = n+1, y > 0):\n//   Sustituimos y por n+1 en (y > 0): (n+1 > 0) = (n > -1) = (n ≥ 0)\n// Como la precondición dada (n ≥ 0) implica (n ≥ 0), la tripleta es correcta.`\n                }\n            ]\n        },\n        {\n            id: \"invariantes\",\n            titulo: \"Invariante de bucle: el coraz\\xf3n del tema\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDD11\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"El invariante de bucle I es un predicado que es verdadero al inicio del bucle, se mantiene verdadero despu\\xe9s de cada iteraci\\xf3n, y junto con la negaci\\xf3n de la condici\\xf3n del bucle implica la postcondici\\xf3n.\"\n                },\n                {\n                    tipo: \"formula\",\n                    contenido: \"Regla del bucle while: {I ∧ B} cuerpo {I}    (I ∧ \\xacB) ⇒ Q\",\n                    explicacion: \"I = invariante. B = condici\\xf3n del bucle. Al salir: se cumple I (por ser invariante) y \\xacB (porque salimos). De I ∧ \\xacB debemos poder deducir Q (postcondici\\xf3n).\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: \"Las 4 condiciones que debe cumplir un invariante\",\n                    contenido: \"1) INICIO: la precondici\\xf3n implica el invariante al entrar. 2) MANTENIMIENTO: si I ∧ B antes del cuerpo, entonces I despu\\xe9s. 3) FIN: I ∧ \\xacB implica la postcondici\\xf3n. 4) TERMINACI\\xd3N: el bucle siempre termina (funci\\xf3n de cota decreciente).\"\n                },\n                {\n                    tipo: \"ejemplo\",\n                    titulo: \"Verificaci\\xf3n completa: contar pares\",\n                    bloques: [\n                        {\n                            tipo: \"codigo\",\n                            lenguaje: \"cpp\",\n                            contenido: `// Especificación:\n// {0 ≤ n ≤ longitud(a)}\n// int contarPares(const vector<int>& a, int n) /* dev c */\n// {c = #i: 0 ≤ i < n : a[i] % 2 = 0}\n\nint contarPares(const vector<int>& a, int n) {\n    int c = 0, k = -1;\n    // INVARIANTE: -1 ≤ k < n  ∧  c = #i: 0 ≤ i ≤ k : a[i]%2 = 0\n    while (k < n-1) {\n        k = k + 1;\n        if (a[k] % 2 == 0) c = c + 1;\n    }\n    return c;\n}`\n                        },\n                        {\n                            tipo: \"lista-numerada\",\n                            items: [\n                                \"INICIO: k=-1, c=0. El rango 0≤i≤-1 est\\xe1 vac\\xedo → c=0=#i en rango vac\\xedo. ✓\",\n                                \"MANTENIMIENTO: Si k<n-1, hacemos k++ y actualizamos c. El invariante se mantiene. ✓\",\n                                \"FIN: Al salir, \\xac(k<n-1) → k=n-1. Con el invariante: c=#i:0≤i<n:a[i]%2=0. ✓\",\n                                \"TERMINACI\\xd3N: n-1-k decrece en 1 cada iteraci\\xf3n hasta 0. ✓\"\n                            ]\n                        }\n                    ]\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"tip\",\n                    titulo: \"Truco para encontrar el invariante\",\n                    contenido: 'El invariante suele ser la postcondici\\xf3n \"generalizada\" reemplazando n por k (o f por f-k). Piensa: \"\\xbfqu\\xe9 propiedad parcial se cumple despu\\xe9s de k iteraciones?\"'\n                }\n            ]\n        },\n        {\n            id: \"esquemas\",\n            titulo: \"Esquemas algor\\xedtmicos iterativos\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDDC2️\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"La mayor\\xeda de algoritmos iterativos siguen uno de estos esquemas. Reconocerlos te permite dise\\xf1ar y verificar algoritmos m\\xe1s f\\xe1cilmente.\"\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"1. B\\xfasqueda lineal\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Patr\\xf3n: buscar elemento que cumple propiedad P\",\n                    lenguaje: \"cpp\",\n                    contenido: `// {0 ≤ n ≤ longitud(v)}\n// int busqueda(vector<int> v, int n, int x)  /* dev p */\n// {(0 ≤ p < n ∧ v[p]=x ∧ ∀j: 0≤j<p: v[j]≠x) ∨ (p=n ∧ ∀j:0≤j<n:v[j]≠x)}\n\nint busqueda(const vector<int>& v, int n, int x) {\n    int i = 0;\n    // INV: 0 ≤ i ≤ n  ∧  ∀j: 0 ≤ j < i : v[j] ≠ x\n    while (i < n && v[i] != x) {\n        i++;\n    }\n    return i;\n}`,\n                    explicacion: \"Al salir: o bien v[i]=x (encontrado) o bien i=n (no encontrado). El invariante garantiza que antes de i no est\\xe1 x.\"\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"2. Variables acumuladoras\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Patr\\xf3n: calcular propiedad acumulativa\",\n                    lenguaje: \"cpp\",\n                    contenido: `// Suma de v[0..n)\n// INV: 0 ≤ k ≤ n  ∧  s = Σi: 0 ≤ i < k : v[i]\nint suma = 0, k = 0;\nwhile (k < n) {\n    suma += v[k];\n    k++;\n}`\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"3. B\\xfasqueda binaria\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"B\\xfasqueda binaria — O(log n)\",\n                    lenguaje: \"cpp\",\n                    contenido: `// {0 ≤ n = longitud(v)  ∧  ∀i: 0≤i<n-1: v[i]≤v[i+1]}\n// INV: 0 ≤ i ≤ f ≤ n  ∧\n//      ∀j: 0≤j<i: v[j]<x  ∧  ∀j: f≤j<n: v[j]≥x\npair<bool,int> busqueda_binaria(const vector<int>& v, int x) {\n    int i = 0, f = v.size();\n    while (i < f) {\n        int m = (i + f) / 2;\n        if (v[m] < x)\n            i = m + 1;  // x está a la derecha\n        else\n            f = m;      // x está a la izquierda o es v[m]\n    }\n    return {i < v.size() && v[i] == x, i};\n}`,\n                    explicacion: \"En cada iteraci\\xf3n el intervalo [i,f) se reduce a la mitad. Al salir, i=f y v[i] es la primera posici\\xf3n ≥ x.\"\n                },\n                {\n                    tipo: \"subtitulo\",\n                    contenido: \"4. Ventana deslizante\",\n                    nivel: 3\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Patr\\xf3n: ventana de tama\\xf1o k sobre el vector\",\n                    lenguaje: \"cpp\",\n                    contenido: `// Busca subvector de longitud k con suma máxima\n// INV: la ventana [i-k, i) está procesada\nint i = 0, suma = 0, maxSuma = INT_MIN;\n// Inicializar primera ventana\nfor (int j = 0; j < k; j++) suma += v[j];\nmaxSuma = suma;\n// Desplazar ventana\nwhile (i + k < n) {\n    suma += v[i + k] - v[i];\n    maxSuma = max(maxSuma, suma);\n    i++;\n}`\n                }\n            ]\n        },\n        {\n            id: \"errores\",\n            titulo: \"Errores frecuentes\",\n            tipo: \"errores\",\n            icono: \"⚠️\",\n            bloques: [\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Invariante incorrecto: el rango es k < n en vez de k ≤ n\",\n                    malo: \"INV: 0 ≤ k < n  ∧  c = #i: 0 ≤ i < k : ...\",\n                    bien: \"INV: -1 ≤ k < n  ∧  c = #i: 0 ≤ i ≤ k : ...\",\n                    explicacion: \"Depende de si k empieza en -1 (y el rango es 0≤i≤k) o en 0 (y el rango es 0≤i<k). Hay que ser coherente con la inicializaci\\xf3n.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"La b\\xfasqueda binaria con intervalo abierto vs cerrado\",\n                    malo: \"Mezclar [i, f] y [i, f) → condiciones de salida incorrectas\",\n                    bien: \"Elegir un convenio y ser consistente: nosotros usamos [i, f) abierto por la derecha\",\n                    explicacion: \"Con [i,f): el bucle es while(i<f), el punto medio es m=(i+f)/2, i=m+1 o f=m. Con [i,f]: el bucle es while(i≤f), i=m+1 o f=m-1.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Invariante que no implica la postcondici\\xf3n\",\n                    malo: \"INV: c = #i: 0≤i<k: a[i]%2=0  (sin la condici\\xf3n de rango de k)\",\n                    bien: \"INV: -1 ≤ k < n  ∧  c = #i: 0≤i≤k: a[i]%2=0\",\n                    explicacion: \"Al salir del bucle (k=n-1), necesitas la condici\\xf3n de rango para que I ∧ \\xacB implique la postcondici\\xf3n.\"\n                }\n            ]\n        },\n        {\n            id: \"resumen\",\n            titulo: \"Resumen y conexi\\xf3n con tests\",\n            tipo: \"tests\",\n            icono: \"\\uD83C\\uDFAF\",\n            bloques: [\n                {\n                    tipo: \"alerta\",\n                    nivel: \"success\",\n                    titulo: \"Lo esencial\",\n                    contenido: \"1) El invariante debe cumplir: inicio, mantenimiento, fin, terminaci\\xf3n. 2) Al salir del bucle: I ∧ \\xacB → postcondici\\xf3n. 3) Los invariantes son especificaciones pre/post del cuerpo del bucle.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"Los tests dan un bucle con invariante propuesto y preguntan si es correcto\",\n                        \"Verifica siempre las 4 condiciones, especialmente que I ∧ \\xacB → Q\",\n                        \"El algoritmo contarPares con k inicializado a -1 es un ejemplo cl\\xe1sico\",\n                        'Busqueda binaria: con [i,f) abierto, la invariante es \"x estar\\xeda en [i,f) si existe\"'\n                    ]\n                }\n            ]\n        }\n    ]\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/lessons/tema3.ts\n");

