eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   tema6: () => (/* binding */ tema6)\n/* harmony export */ });\nconst tema6 = {\n    id: 6,\n    titulo: \"Vuelta atr\\xe1s\",\n    subtitulo: \"Exploraci\\xf3n sistem\\xe1tica del espacio de soluciones\",\n    descripcion: \"Aprende el esquema backtracking: c\\xf3mo construir soluciones progresivamente, podar el espacio de b\\xfasqueda y resolver problemas de optimizaci\\xf3n.\",\n    color: \"from-slate-600 to-slate-800\",\n    icono: \"\\uD83D\\uDD19\",\n    topicKey: \"Tema 6_ Vuelta atr\\xe1s\",\n    duracion: \"50 min\",\n    sections: [\n        {\n            id: \"cuando-usar\",\n            titulo: \"\\xbfCu\\xe1ndo usar Vuelta Atr\\xe1s?\",\n            tipo: \"intro\",\n            icono: \"\\uD83E\\uDD14\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Vuelta Atr\\xe1s (Backtracking) es la t\\xe9cnica de \\xfaltimo recurso: se usa cuando no existe ning\\xfan algoritmo eficiente para resolver el problema y la \\xfanica opci\\xf3n es explorar todas las soluciones posibles de forma estructurada.\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"warning\",\n                    titulo: \"\\xbfCu\\xe1ndo NO usar Backtracking?\",\n                    contenido: \"Si existe un algoritmo greedy (voraz), din\\xe1mico, DyV u otro que resuelve el problema con menor coste, \\xfasalo. Backtracking es fuerza bruta estructurada — su coste es exponencial o factorial en el peor caso.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"✅ Problemas de satisfactibilidad: \\xbfexiste alguna soluci\\xf3n que cumpla las restricciones?\",\n                        \"✅ Encontrar TODAS las soluciones v\\xe1lidas\",\n                        \"✅ Optimizaci\\xf3n combinatoria: encontrar la mejor soluci\\xf3n de entre todas\",\n                        \"❌ Si existe algoritmo polin\\xf3mico: Backtracking es innecesario\"\n                    ]\n                },\n                {\n                    tipo: \"texto\",\n                    contenido: \"La mochila 0-1 (versi\\xf3n entera) no se puede resolver con greedy, por eso necesita Backtracking. En cambio la mochila fraccionaria S\\xcd tiene soluci\\xf3n greedy \\xf3ptima.\"\n                }\n            ]\n        },\n        {\n            id: \"esquema\",\n            titulo: \"El esquema general\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDDC2️\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"En Backtracking, la soluci\\xf3n es una tupla ⟨x₀, x₁, ..., xₙ⟩ donde cada xᵢ ∈ Sᵢ. Se construye progresivamente: en cada nivel k elegimos un valor para xₖ y comprobamos si podemos continuar.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Esquema b\\xe1sico — encontrar todas las soluciones\",\n                    lenguaje: \"cpp\",\n                    contenido: `// k es el nivel actual (posición en la solución parcial)\nvoid vuelta_atras(tuple& sol, int k) {\n    for (c : candidatos(k)) {        // para cada posible valor en nivel k\n        sol[k] = c;\n        if (es_solucion(sol, k))\n            procesar_solucion(sol);  // guardar, mostrar, contar...\n        else if (es_completable(sol, k))\n            vuelta_atras(sol, k+1); // continuar al siguiente nivel\n    }\n}`,\n                    explicacion: \"sol contiene la soluci\\xf3n parcial hasta el nivel k-1. Para cada candidato en el nivel k, comprueba si ya es soluci\\xf3n completa o si puede extenderse.\"\n                },\n                {\n                    tipo: \"tabla\",\n                    cabeceras: [\n                        \"Funci\\xf3n\",\n                        \"Cu\\xe1ndo devuelve true\",\n                        \"Cu\\xe1ndo se llama\"\n                    ],\n                    filas: [\n                        [\n                            \"es_solucion(sol, k)\",\n                            \"k es el \\xfaltimo nivel Y las restricciones se cumplen\",\n                            \"Antes de llamar recursivamente\"\n                        ],\n                        [\n                            \"es_completable(sol, k)\",\n                            \"k NO es el \\xfaltimo nivel Y podr\\xeda haber soluci\\xf3n\",\n                            \"Para decidir si merece la pena continuar\"\n                        ],\n                        [\n                            \"candidatos(k)\",\n                            \"Valores v\\xe1lidos para sol[k] (restricciones expl\\xedcitas)\",\n                            \"Al inicio del bucle de cada nivel\"\n                        ]\n                    ]\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: \"Restricciones expl\\xedcitas vs. impl\\xedcitas\",\n                    contenido: \"Expl\\xedcitas: los conjuntos Sᵢ de donde viene cada componente (ej: xi ∈ {0,1,2,3}). Impl\\xedcitas: relaciones que deben cumplir las componentes entre s\\xed (ej: no se ataquen en el tablero de ajedrez).\"\n                }\n            ]\n        },\n        {\n            id: \"cuatro-reinas\",\n            titulo: \"Ejemplo: 4 Reinas\",\n            tipo: \"ejemplo\",\n            icono: \"♛\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Colocar 4 reinas en un tablero 4\\xd74 de forma que ninguna se ataque. La soluci\\xf3n es una tupla ⟨x₀, x₁, x₂, x₃⟩ donde xᵢ ∈ {0,1,2,3} es la fila de la reina de la columna i.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Verificar si dos reinas se atacan\",\n                    lenguaje: \"cpp\",\n                    contenido: `bool no_ataca(const tuple& sol, int k) {\n    // Comprueba que la reina en columna k no ataca a las anteriores\n    bool b = true;\n    int i = 0;\n    while (b && i < k) {\n        b = (sol[i] != sol[k])  // misma fila\n         && (sol[i] - sol[k] != i - k)   // diagonal descendente\n         && (sol[i] - sol[k] != k - i);  // diagonal ascendente\n        ++i;\n    }\n    return b;\n}\n\nbool es_solucion(const tuple& sol, int k) {\n    return (k == 3) && no_ataca(sol, k);\n}\n\nbool es_completable(const tuple& sol, int k) {\n    return (k < 3) && no_ataca(sol, k);\n}`\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"tip\",\n                    titulo: \"Condici\\xf3n de diagonal\",\n                    contenido: \"Dos reinas en (col1, fila1) y (col2, fila2) est\\xe1n en la misma diagonal si |col1-col2| = |fila1-fila2|. Equivalentemente: fila1-fila2 = \\xb1(col1-col2).\"\n                }\n            ]\n        },\n        {\n            id: \"marcaje\",\n            titulo: \"Vuelta atr\\xe1s con marcaje\",\n            tipo: \"concepto\",\n            icono: \"\\uD83C\\uDFF7️\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: 'El marcaje es una optimizaci\\xf3n que usa arrays auxiliares para evitar recalcular la funci\\xf3n es_completable desde cero en cada llamada. En vez de comprobar si hay conflictos revisando toda la soluci\\xf3n parcial, se mantiene un registro de qu\\xe9 posiciones est\\xe1n \"bloqueadas\".'\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"4 Reinas con marcaje — O(1) en es_completable\",\n                    lenguaje: \"cpp\",\n                    contenido: `bool filas[4] = {false};          // filas ocupadas\nbool diag_asc[7] = {false};       // diagonales ascendentes (x+y)\nbool diag_desc[7] = {false};      // diagonales descendentes (x-y+3)\n\nvoid cuatro_reinas_marcaje(tuple& sol, int k) {\n    for (int c = 0; c < 4; c++) {\n        if (!filas[c] && !diag_asc[k+c] && !diag_desc[k-c+3]) {\n            // Marcar\n            sol[k] = c;\n            filas[c] = diag_asc[k+c] = diag_desc[k-c+3] = true;\n\n            if (k == 3)\n                mostrar(sol);\n            else\n                cuatro_reinas_marcaje(sol, k+1);\n\n            // Desmarcar (CRUCIAL: deshacer al volver)\n            filas[c] = diag_asc[k+c] = diag_desc[k-c+3] = false;\n        }\n    }\n}`,\n                    explicacion: \"La comprobaci\\xf3n pasa de O(k) a O(1). El truco: al hacer backtrack, se DESMARCA lo que se marc\\xf3.\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"danger\",\n                    titulo: \"El desmarcar es OBLIGATORIO\",\n                    contenido: \"Si no desmarcas al hacer backtrack, los niveles superiores seguir\\xe1n viendo las posiciones como bloqueadas aunque ya no estemos en esa rama. Es el error m\\xe1s com\\xfan en backtracking con marcaje.\"\n                }\n            ]\n        },\n        {\n            id: \"optimizacion\",\n            titulo: \"Backtracking con optimizaci\\xf3n\",\n            tipo: \"concepto\",\n            icono: \"\\uD83C\\uDFC6\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Cuando queremos MINIMIZAR o MAXIMIZAR, el esquema cambia: llevamos registro de la mejor soluci\\xf3n encontrada hasta ahora (coste_min o coste_max) y usamos podas para evitar explorar ramas que no pueden mejorarla.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Esquema de optimizaci\\xf3n\",\n                    lenguaje: \"cpp\",\n                    contenido: `void vuelta_atras_opt(tuple& sol, int k, int& mejor_coste) {\n    for (c : candidatos(k)) {\n        sol[k] = c;\n        if (es_solucion(sol, k)) {\n            int coste_actual = calcular_coste(sol);\n            if (coste_actual < mejor_coste) {\n                mejor_coste = coste_actual;\n                guardar_mejor_sol(sol);\n            }\n        } else if (es_completable(sol, k)\n                && poda_optimalidad(sol, k, mejor_coste)) {\n            vuelta_atras_opt(sol, k+1, mejor_coste);\n        }\n    }\n}`\n                },\n                {\n                    tipo: \"tabla\",\n                    cabeceras: [\n                        \"Tipo de poda\",\n                        \"Cu\\xe1ndo se usa\",\n                        \"Efectividad\"\n                    ],\n                    filas: [\n                        [\n                            \"Satisfactibilidad\",\n                            \"Cuando la soluci\\xf3n parcial viola restricciones (imposible extender)\",\n                            \"Siempre: evita ramas sin soluci\\xf3n\"\n                        ],\n                        [\n                            \"Optimalidad\",\n                            \"Cuando la soluci\\xf3n parcial ya es peor que la mejor encontrada\",\n                            \"Cuando el coste solo puede crecer\"\n                        ]\n                    ]\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"warning\",\n                    titulo: \"Coste de la poda\",\n                    contenido: \"La poda de optimalidad puede ser tan costosa que no compense: si calcular la poda es m\\xe1s caro que el ahorro que produce, el algoritmo total puede ser m\\xe1s lento. Es una decisi\\xf3n de dise\\xf1o que depende del problema.\"\n                }\n            ]\n        },\n        {\n            id: \"mochila\",\n            titulo: \"Mochila 0-1: ejemplo de optimizaci\\xf3n\",\n            tipo: \"ejemplo\",\n            icono: \"\\uD83C\\uDF92\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Dado un conjunto de objetos con pesos y valores, y una mochila con capacidad m\\xe1xima, \\xbfqu\\xe9 objetos meter para maximizar el valor sin superar la capacidad?\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: \"\\xbfPor qu\\xe9 no sirve greedy?\",\n                    contenido: \"Ninguna estrategia greedy funciona: ni mayor valor, ni menor peso, ni mayor valor/peso. Contraejemplo: mochila peso 6, objetos {peso:5,valor:10} y {peso:2,valor:6} y {peso:3,valor:5}. El greedy por valor da 10, pero {6,5}={11} es mejor.\"\n                },\n                {\n                    tipo: \"codigo\",\n                    titulo: \"Esquema de soluci\\xf3n con backtracking\",\n                    lenguaje: \"cpp\",\n                    contenido: `// sol[k] = true si metemos el objeto k, false si no\n// pago = coste acumulado, max_val = mejor valor encontrado\nvoid mochila(int k, int peso_actual, int val_actual,\n             int& max_val, tuple& mejor_sol) {\n    if (k == N) {  // hemos decidido sobre todos los objetos\n        if (val_actual > max_val) {\n            max_val = val_actual;\n            guardar(mejor_sol);\n        }\n        return;\n    }\n\n    // PODA satisfactibilidad: si me excedo de peso, no continúo\n    // PODA optimalidad: si aunque meta todo lo que queda no mejoro\n    if (poda_satisfactibilidad(k, peso_actual)\n     && poda_optimalidad(k, val_actual, max_val)) {\n\n        // Opción 1: meter el objeto k\n        if (peso_actual + peso[k] <= capacidad) {\n            sol[k] = true;\n            mochila(k+1, peso_actual + peso[k], val_actual + valor[k],\n                    max_val, mejor_sol);\n        }\n\n        // Opción 2: no meter el objeto k\n        sol[k] = false;\n        mochila(k+1, peso_actual, val_actual, max_val, mejor_sol);\n    }\n}`\n                }\n            ]\n        },\n        {\n            id: \"complejidad\",\n            titulo: \"Complejidad y limitaciones\",\n            tipo: \"concepto\",\n            icono: \"\\uD83D\\uDCCA\",\n            bloques: [\n                {\n                    tipo: \"texto\",\n                    contenido: \"Sin podas, el \\xe1rbol de exploraci\\xf3n tiene tama\\xf1o proporcional a a^h (a opciones por nivel, h niveles). Con podas eficientes puede reducirse enormemente, pero el peor caso sigue siendo exponencial.\"\n                },\n                {\n                    tipo: \"alerta\",\n                    nivel: \"info\",\n                    titulo: \"No todos los backtrackings son exponenciales\",\n                    contenido: \"Si el espacio de soluciones es polin\\xf3mico, el backtracking tambi\\xe9n puede serlo. En la pr\\xe1ctica, con buenas podas los algoritmos backtracking son aplicables a instancias medianas de muchos problemas reales.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"\\xc1rbol de exploraci\\xf3n: altura h = longitud de la soluci\\xf3n, anchura a = n\\xba candidatos por nivel\",\n                        \"Sin podas: coste = a^h (exponencial o factorial)\",\n                        \"Con podas: se eliminan ramas enteras; en la pr\\xe1ctica puede ser mucho mejor\",\n                        \"Solo aplicable a instancias peque\\xf1as o medianas\"\n                    ]\n                }\n            ]\n        },\n        {\n            id: \"errores\",\n            titulo: \"Errores frecuentes\",\n            tipo: \"errores\",\n            icono: \"⚠️\",\n            bloques: [\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"No desmarcar al hacer backtrack\",\n                    malo: \"filas[c] = true; vuelta_atras(sol, k+1); // sin desmarcar\",\n                    bien: \"filas[c] = true; vuelta_atras(sol, k+1); filas[c] = false;\",\n                    explicacion: 'El desmarque es el \"volver atr\\xe1s\". Sin \\xe9l, las restricciones quedan activas para otras ramas y se pierden soluciones v\\xe1lidas.'\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"Confundir es_solucion con es_completable\",\n                    malo: \"es_solucion retorna true cuando k < N (no es completa todav\\xeda)\",\n                    bien: \"es_solucion retorna true solo cuando k = N-1 (\\xfaltimo nivel) y se cumplen todas las restricciones\",\n                    explicacion: \"es_solucion verifica que la tupla est\\xe1 completa y es v\\xe1lida. es_completable verifica que la tupla parcial puede extenderse a una soluci\\xf3n.\"\n                },\n                {\n                    tipo: \"error-frecuente\",\n                    titulo: \"La poda de optimalidad no siempre compensa\",\n                    malo: '\"Siempre es mejor a\\xf1adir poda de optimalidad\"',\n                    bien: \"Si la poda es costosa de calcular, puede no valer la pena\",\n                    explicacion: \"La poda reduce nodos explorados, pero si el c\\xe1lculo de la poda consume m\\xe1s tiempo del que ahorra, el algoritmo es m\\xe1s lento con ella.\"\n                }\n            ]\n        },\n        {\n            id: \"resumen\",\n            titulo: \"Resumen y conexi\\xf3n con tests\",\n            tipo: \"tests\",\n            icono: \"\\uD83C\\uDFAF\",\n            bloques: [\n                {\n                    tipo: \"alerta\",\n                    nivel: \"success\",\n                    titulo: \"Lo esencial\",\n                    contenido: \"1) Backtracking = construir soluciones progresivamente, deshacer si no funciona. 2) Siempre DESMARCAR al retroceder. 3) Dos tipos de poda: satisfactibilidad (viola restricciones) y optimalidad (no puede mejorar). 4) La poda puede no compensar si es costosa.\"\n                },\n                {\n                    tipo: \"lista\",\n                    items: [\n                        \"La mochila entera NO se puede resolver con greedy → necesita backtracking\",\n                        \"Todos los algoritmos backtracking son exponenciales en el PEOR caso\",\n                        \"Con marcaje, la verificaci\\xf3n de restricciones pasa de O(k) a O(1)\",\n                        \"Funci\\xf3n de factibilidad = es_completable (\\xbfpuede esta soluci\\xf3n parcial extenderse?)\"\n                    ]\n                }\n            ]\n        }\n    ]\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/lessons/tema6.ts\n");

